1	package com.fortinet.nac.ingestion.consumer.handler;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.util.StatusOr;
6	import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
7	import com.fortinet.nac.ingestion.consumer.handler.interfaces.FingerprintHandler;
8	import com.fortinet.nac.ingestion.entity.Entity;
