1	package com.fortinet.nac.ingestion.consumer.handler;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.redis.DistributedLock;
6	import com.fortinet.nac.common.util.StatusOr;
7	import com.fortinet.nac.ingestion.consumer.EntityAttributeFingerprintBuilder;
8	
9	import com.fortinet.nac.ingestion.consumer.handler.enums.FingerprintCase;
10	import com.fortinet.nac.ingestion.consumer.handler.interfaces.FingerprintHandler;
11	import com.fortinet.nac.ingestion.consumer.handler.registry.FingerprintHandlerRegistry;
12	import com.fortinet.nac.ingestion.entity.Entity;
13	import com.fortinet.nac.ingestion.service.EntityService;
14	import com.fortinet.nac.ingestion.util.RedisUtil;
15	import lombok.RequiredArgsConstructor;
16	import lombok.extern.slf4j.Slf4j;
17	import org.redisson.api.StreamMessageId;
18	import org.springframework.stereotype.Component;
19	
20	@Slf4j
21	@Component
22	@RequiredArgsConstructor
23	public class CachedExistingEntityHandler {
24	
25	    private final EntityService entityService;
26	    private final EntityAttributeFingerprintBuilder entityAttributeFingerprintBuilder;
27	    private final DistributedLock distributedLock;
28	    private final FingerprintHandlerRegistry fingerprintHandlerRegistry;
29	
30	    public StatusOr<Entity> handle(IngestionRequest req, Long cachedEntityId) {
31	
32	        Entity e = entityService.getEntity(cachedEntityId);
33	        if (e == null) {
34	            log.error("Entity id={} not found in DB, req={}", cachedEntityId, req);
35	            return StatusOr.error(Constants.BusinesCode.ENTITY_NOT_FOUND, "entity not found");
36	        }
37	
38	        // version check: determine whether the current request is older than
39	        // what's already stored in the DB.
40	        StreamMessageId reqId = safeParseStreamId(req.getVersion(), "req.version", req);
41	        StreamMessageId dbId  = safeParseStreamId(e.getLastReqVersion(), "entity.lastReqVersion", req);
42	
43	        if (reqId != null && dbId != null && compareStreamMessageId(reqId, dbId) < 0) {
44	            // A newer request has already been processed,
45	            // so this message is considered outdated.
46	            log.warn("Skip stale request. reqStreamId={}, dbStreamId={}, entityId={}",
47	                    reqId, dbId, e.getId());
48	            return StatusOr.ok(e); // Directly return without modifying the entity
49	        }
50	
51	        String dbFp = e.getAttributeFingerprint();
52	
53	        String reqFp = req.getAttributeFingerprint();
54	        if (reqFp == null || reqFp.isBlank()) {
55	            log.info("Request fingerprint is empty, fallback to full attribute-based calculation. entityId={}, reqId={}",
56	                    cachedEntityId, req.getRequestId());
57	            reqFp = entityAttributeFingerprintBuilder.build(req).getFingerprint();
58	            req.setAttributeFingerprint(reqFp);
59	        }
60	
61	        String processLockKey = RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX, req);
62	        boolean acquired = distributedLock.tryLock(processLockKey, Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL);
63	
64	        boolean sameFingerprint = dbFp != null && dbFp.equals(reqFp);
65	        FingerprintCase fpCase = FingerprintCase.of(sameFingerprint, acquired);
66	        log.info("CachedExistingEntityHandler: entityId={}, sameFp={}, lockAcquired={}, case={}",
67	                e.getId(), sameFingerprint, acquired, fpCase);
68	
69	        FingerprintHandler handler = fingerprintHandlerRegistry.get(fpCase);
70	        if (handler == null) {
71	            log.error("No handler found for case={}", fpCase);
72	            return StatusOr.error("no handler for fingerprint case: " + fpCase);
73	        }
74	
75	        try {
76	            return handler.handle(req, e, reqFp);
77	        } finally {
78	            if (acquired) {
79	                distributedLock.unLock(processLockKey);
80	            }
81	        }
82	    }
83	
84	    private StreamMessageId safeParseStreamId(String raw, String field, IngestionRequest req) {
85	        if (raw == null || raw.isBlank()) {
86	            log.debug("Missing {}. Skip stream-id check. entityType={}, reqId={}",
87	                    field, req.getEntityType(), req.getRequestId());
88	            return null;
89	        }
90	
91	        try {
92	            int dash = raw.indexOf('-');
93	            if (dash < 0) {
94	                log.warn("Invalid Redis Stream ID: {}", raw);
95	                return null;
96	            }
97	            long ms = Long.parseLong(raw.substring(0, dash));
98	            long seq = Long.parseLong(raw.substring(dash + 1));
99	            return new StreamMessageId(ms, seq);
100	        } catch (RuntimeException ex) {
101	            log.warn("Invalid {}='{}'. Skip stream-id check. reqId={}, err={}",
102	                    field, raw, req.getRequestId(), ex.toString());
103	            return null;
104	        }
105	    }
106	
107	    private int compareStreamMessageId(StreamMessageId reqId, StreamMessageId dbId) {
108	        String reqIdStr = reqId.toString();
109	        String dbIdStr = dbId.toString();
110	
111	        // Parse timestamp and sequence from the string representation "timestamp-sequence"
112	        int reqDashIndex = reqIdStr.indexOf('-');
113	        int dbDashIndex = dbIdStr.indexOf('-');
114	
115	        if (reqDashIndex > 0 && dbDashIndex > 0) {
116	            long reqTimestamp = Long.parseLong(reqIdStr.substring(0, reqDashIndex));
117	            long dbTimestamp = Long.parseLong(dbIdStr.substring(0, dbDashIndex));
118	
119	            if (reqTimestamp != dbTimestamp) {
120	                return Long.compare(reqTimestamp, dbTimestamp);
121	            }
122	
123	            long reqSequence = Long.parseLong(reqIdStr.substring(reqDashIndex + 1));
124	            long dbSequence = Long.parseLong(dbIdStr.substring(dbDashIndex + 1));
125	            return Long.compare(reqSequence, dbSequence);
126	        }
127	
128	        // Fallback to string comparison if parsing fails
129	        return reqIdStr.compareTo(dbIdStr);
130	    }
131	}
