package com.fortinet.nac.ingestion.config;

import com.bsc.database.PersistenceSnowflakeIdGenerator;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.Primary;

@Configuration("ingestionIdGeneratorConfig")
public class IdGeneratorConfig {

    @Bean("ingestionIdGenerator")
    public PersistenceSnowflakeIdGenerator defaultIdGenerator(
        @Value("${id.generator.data-center-id:0}") int dataCenterId,
        @Value("${id.generator.worker-id:0}") int workerId,
        @Value("${id.generator.data-server-id:ingest}") String dataServerId,
        @Value("${id.generator.interval-seconds:10}") int intervalSeconds,
        @Value("${id.generator.module:7}") int module,
        @Value("${id.generator.base-dir:/bsc/campusMgr/config}") String baseDir
    ) {
        java.nio.file.Path path = java.nio.file.Paths.get(baseDir);

        PersistenceSnowflakeIdGenerator.Manager.initDefaults(
            dataCenterId, workerId, dataServerId, intervalSeconds, module, path
        );
        return PersistenceSnowflakeIdGenerator.Manager.createIdGenerator();
    }
}

