package com.fortinet.nac.ingestion.consumer.handler;

import com.fortinet.nac.common.Constants;
import com.fortinet.nac.common.dto.IngestionRequest;
import com.fortinet.nac.common.redis.DistributedLock;
import com.fortinet.nac.common.util.StatusOr;
import com.fortinet.nac.ingestion.consumer.EntityAttributeFingerprintBuilder;

import com.fortinet.nac.ingestion.consumer.handler.enums.FingerprintCase;
import com.fortinet.nac.ingestion.consumer.handler.interfaces.FingerprintHandler;
import com.fortinet.nac.ingestion.consumer.handler.registry.FingerprintHandlerRegistry;
import com.fortinet.nac.ingestion.entity.Entity;
import com.fortinet.nac.ingestion.service.EntityService;
import com.fortinet.nac.ingestion.util.RedisUtil;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.redisson.api.StreamMessageId;
import org.springframework.stereotype.Component;

@Slf4j
@Component
@RequiredArgsConstructor
public class CachedExistingEntityHandler {

    private final EntityService entityService;
    private final EntityAttributeFingerprintBuilder entityAttributeFingerprintBuilder;
    private final DistributedLock distributedLock;
    private final FingerprintHandlerRegistry fingerprintHandlerRegistry;

    public StatusOr<Entity> handle(IngestionRequest req, Long cachedEntityId) {

        Entity e = entityService.getEntity(cachedEntityId);
        if (e == null) {
            log.error("Entity id={} not found in DB, req={}", cachedEntityId, req);
            return StatusOr.error(Constants.BusinesCode.ENTITY_NOT_FOUND, "entity not found");
        }

        // version check: determine whether the current request is older than
        // what's already stored in the DB.
        StreamMessageId reqId = safeParseStreamId(req.getVersion(), "req.version", req);
        StreamMessageId dbId  = safeParseStreamId(e.getLastReqVersion(), "entity.lastReqVersion", req);

        if (reqId != null && dbId != null && compareStreamMessageId(reqId, dbId) < 0) {
            // A newer request has already been processed,
            // so this message is considered outdated.
            log.warn("Skip stale request. reqStreamId={}, dbStreamId={}, entityId={}",
                    reqId, dbId, e.getId());
            return StatusOr.ok(e); // Directly return without modifying the entity
        }

        String dbFp = e.getAttributeFingerprint();

        String reqFp = req.getAttributeFingerprint();
        if (reqFp == null || reqFp.isBlank()) {
            log.info("Request fingerprint is empty, fallback to full attribute-based calculation. entityId={}, reqId={}",
                    cachedEntityId, req.getRequestId());
            reqFp = entityAttributeFingerprintBuilder.build(req).getFingerprint();
            req.setAttributeFingerprint(reqFp);
        }

        String processLockKey = RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX, req);
        boolean acquired = distributedLock.tryLock(processLockKey, Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL);

        boolean sameFingerprint = dbFp != null && dbFp.equals(reqFp);
        FingerprintCase fpCase = FingerprintCase.of(sameFingerprint, acquired);
        log.info("CachedExistingEntityHandler: entityId={}, sameFp={}, lockAcquired={}, case={}",
                e.getId(), sameFingerprint, acquired, fpCase);

        FingerprintHandler handler = fingerprintHandlerRegistry.get(fpCase);
        if (handler == null) {
            log.error("No handler found for case={}", fpCase);
            return StatusOr.error("no handler for fingerprint case: " + fpCase);
        }

        try {
            return handler.handle(req, e, reqFp);
        } finally {
            if (acquired) {
                distributedLock.unLock(processLockKey);
            }
        }
    }

    private StreamMessageId safeParseStreamId(String raw, String field, IngestionRequest req) {
        if (raw == null || raw.isBlank()) {
            log.debug("Missing {}. Skip stream-id check. entityType={}, reqId={}",
                    field, req.getEntityType(), req.getRequestId());
            return null;
        }

        try {
            int dash = raw.indexOf('-');
            if (dash < 0) {
                log.warn("Invalid Redis Stream ID: {}", raw);
                return null;
            }
            long ms = Long.parseLong(raw.substring(0, dash));
            long seq = Long.parseLong(raw.substring(dash + 1));
            return new StreamMessageId(ms, seq);
        } catch (RuntimeException ex) {
            log.warn("Invalid {}='{}'. Skip stream-id check. reqId={}, err={}",
                    field, raw, req.getRequestId(), ex.toString());
            return null;
        }
    }

    private int compareStreamMessageId(StreamMessageId reqId, StreamMessageId dbId) {
        String reqIdStr = reqId.toString();
        String dbIdStr = dbId.toString();

        // Parse timestamp and sequence from the string representation "timestamp-sequence"
        int reqDashIndex = reqIdStr.indexOf('-');
        int dbDashIndex = dbIdStr.indexOf('-');

        if (reqDashIndex > 0 && dbDashIndex > 0) {
            long reqTimestamp = Long.parseLong(reqIdStr.substring(0, reqDashIndex));
            long dbTimestamp = Long.parseLong(dbIdStr.substring(0, dbDashIndex));

            if (reqTimestamp != dbTimestamp) {
                return Long.compare(reqTimestamp, dbTimestamp);
            }

            long reqSequence = Long.parseLong(reqIdStr.substring(reqDashIndex + 1));
            long dbSequence = Long.parseLong(dbIdStr.substring(dbDashIndex + 1));
            return Long.compare(reqSequence, dbSequence);
        }

        // Fallback to string comparison if parsing fails
        return reqIdStr.compareTo(dbIdStr);
    }
}
